interface BeninMapInteractiveProps {
  onSelectDepartment?: (id: string) => void;
}

const BeninMapInteractive = ({ onSelectDepartment }: BeninMapInteractiveProps) => {
  const [hoveredDept, setHoveredDept] = useState<string | null>(null);
  const [selectedDept, setSelectedDept] = useState<string | null>(null);

  const accentColor = '#d04a25';
  const defaultColor = '#D1CEC5';

  const handleClick = (deptId: string) => {
    setSelectedDept(deptId);
    onSelectDepartment?.(deptId);
  };

  const getFill = (deptId: string) => {
    if (selectedDept === deptId) return accentColor;
    if (hoveredDept === deptId) return '#e85a35';
    return defaultColor;
  };

  return (
    <div className="relative w-full max-w-2xl mx-auto">
      <svg
        viewBox="0 0 393 781"
        className="w-full h-auto drop-shadow-2xl"
        xmlns="http://www.w3.org/2000/svg"
      >
        {departments.map((dept) => (
          <motion.path
            key={dept.id}
            d={dept.path}
            fill={getFill(dept.id)}
            stroke="#FFFFFF"
            strokeWidth="3"
            strokeLinecap="round"
            strokeLinejoin="round"
            className="cursor-pointer"
            onMouseEnter={() => setHoveredDept(dept.id)}
            onMouseLeave={() => setHoveredDept(null)}
            onClick={() => handleClick(dept.id)}
            animate={{ fill: getFill(dept.id) }}
            transition={{ duration: 0.3 }}
            whileHover={{ scale: 1.01 }}
          />
        ))}
      </svg>

      {hoveredDept && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="absolute top-4 left-1/2 transform -translate-x-1/2 pointer-events-none z-10"
        >
          <div className="bg-white px-6 py-3 rounded-xl shadow-2xl border-2 border-[#d04a25]">
            <p className="font-bold text-gray-800 text-base">
              {departments.find(d => d.id === hoveredDept)?.name}
            </p>
            <p className="text-sm text-gray-600">
              {departments.find(d => d.id === hoveredDept)?.communes} communes
            </p>
          </div>
        </motion.div>
      )}

      <div className="mt-6 flex items-center justify-center gap-6 text-sm">
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full" style={{ backgroundColor: defaultColor }} />
          <span className="text-gray-600">Département</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full" style={{ backgroundColor: accentColor }} />
          <span className="text-gray-600">Sélectionné</span>
        </div>
      </div>

      {selectedDept && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mt-6 p-6 bg-gradient-to-br from-[#d04a25]/10 to-[#d04a25]/5 rounded-2xl border-2 border-[#d04a25]/20"
        >
          <h3 className="text-2xl font-bold text-gray-800 mb-2">
            {departments.find(d => d.id === selectedDept)?.name}
          </h3>
          <p className="text-gray-600">
            <span className="font-semibold">{departments.find(d => d.id === selectedDept)?.communes}</span> communes
          </p>
        </motion.div>
      )}
    </div>
  );
};

export default BeninMapInteractive;
